import type { ContextEntityType } from 'shared';
import type { AuthContext } from '#/core/context';
import { invalidateCache } from '#/middlewares/guard/invalidate-cache';
import { deleteMembershipsByIds, findMembershipsByUserIdsAndContext } from '#/modules/memberships/memberships-queries';
import { getValidContextEntity } from '#/permissions/get-context-entity';
import { logEvent } from '#/utils/logger';

interface DeleteMembershipsInput {
  ids: string[];
  entityId: string;
  entityType: ContextEntityType;
}

export async function deleteMembershipsOp(ctx: AuthContext, input: DeleteMembershipsInput) {
  const { ids, entityId, entityType } = input;

  const { entity } = await getValidContextEntity(ctx, entityId, entityType, 'delete');

  const membershipIds = Array.isArray(ids) ? ids : [ids];

  const targets = await findMembershipsByUserIdsAndContext(ctx, {
    userIds: membershipIds,
    contextId: entity.id,
  });

  const rejectedIds: string[] = [];

  for (const id of membershipIds) {
    if (!targets.some((target) => target.userId === id)) rejectedIds.push(id);
  }

  if (targets.length === 0) return { data: [] as never[], rejectedIds };

  await deleteMembershipsByIds(ctx, {
    ids: targets.map((target) => target.id),
  });

  for (const target of targets) invalidateCache.user(target.userId);

  logEvent(ctx, 'info', 'Memberships deleted', { count: targets.length, ids: targets.map((t) => t.userId) });

  return { data: [] as never[], rejectedIds };
}

import type { AuthContext } from '#/core/context';
import type { tenantsTable } from '#/db/schema/tenants';
import { invalidateCache } from '#/middlewares/guard/invalidate-cache';
import { createTenantForUser } from '#/modules/tenants/tenant-service';
import { countDomainsByTenant, updateTenant } from '#/modules/tenants/tenants-queries';

interface CreateTenantInput {
  name: string;
  status?: string;
}

export async function createTenantOp(ctx: AuthContext, input: CreateTenantInput) {
  const db = ctx.var.db;
  const user = ctx.var.user;
  const { name, status } = input;

  const tenant = await createTenantForUser(
    db,
    {
      name,
      createdBy: user.id,
      userEmail: user.email,
    },
    ctx,
  );

  // Apply status override if provided (createTenantForUser defaults to 'active')
  if (status && status !== 'active') {
    const updated = await updateTenant(ctx, {
      targetTenantId: tenant.id,
      values: { status: status as typeof tenantsTable.$inferInsert.status },
    });
    invalidateCache.tenant(tenant.id);
    const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: tenant.id });
    return { ...updated, domainsCount };
  }

  const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: tenant.id });
  return { ...tenant, domainsCount };
}

import { eq } from 'drizzle-orm';
import type { AuthContext } from '#/core/context';
import { AppError } from '#/core/error';
import { tenantsTable } from '#/db/schema/tenants';
import { createTenantForUser } from '#/modules/tenants/tenant-service';
import { countDomainsByTenant } from '#/modules/tenants/tenants-queries';

interface SelfCreateTenantInput {
  name: string;
}

export async function selfCreateTenantOp(ctx: AuthContext, input: SelfCreateTenantInput) {
  const db = ctx.var.db;
  const user = ctx.var.user;
  const memberships = ctx.var.memberships;

  // Block if user already has memberships (already in a tenant with orgs)
  if (memberships.length > 0) {
    throw new AppError(409, 'restrict_by_app', 'warn', {
      message: 'User already has tenant memberships',
    });
  }

  // If user already created a tenant (e.g. previous attempt where org creation failed), return it
  const [existingTenant] = await db.select().from(tenantsTable).where(eq(tenantsTable.createdBy, user.id)).limit(1);

  if (existingTenant) {
    const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: existingTenant.id });
    return { ...existingTenant, domainsCount };
  }

  const tenant = await createTenantForUser(
    db,
    {
      name: input.name,
      createdBy: user.id,
      userEmail: user.email,
    },
    ctx,
  );

  const domainsCount = await countDomainsByTenant(ctx, { targetTenantId: tenant.id });
  return { ...tenant, domainsCount };
}

