import { Hono } from 'hono'
import { createMiddleware } from 'hono/factory'
import { Counter } from './counter'

type Env = {
  Bindings: {
    COUNTERS: DurableObjectNamespace<Counter>
  }
  Variables: {
    count: number
    stub: DurableObjectStub<Counter>
  }
}

const app = new Hono<Env>()

const durableObjectMiddleware = createMiddleware<Env>(async (c, next) => {
  const name = c.req.query('name')
  if (!name) {
    return c.text(
      'Select a Durable Object to contact by using the `name` URL query string parameter, for example, ?name=A'
    )
  }
  const id = c.env.COUNTERS.idFromName(name)
  const stub = c.env.COUNTERS.get(id)
  c.set('stub', stub)
  await next()
  c.res = c.text(`Durable Object '${name}' count: ${c.var.count}`)
})

app.get('/', durableObjectMiddleware, async (c, next) => {
  const count = await c.var.stub.getCounterValue()
  c.set('count', count)
  await next()
})

app.get('/increment', durableObjectMiddleware, async (c, next) => {
  const count = await c.var.stub.increment()
  c.set('count', count)
  await next()
})

app.get('/decrement', durableObjectMiddleware, async (c, next) => {
  const count = await c.var.stub.decrement()
  c.set('count', count)
  await next()
})

export { Counter }

export default app

import type { Context, MiddlewareHandler } from 'hono'
import { Toucan } from 'toucan-js'
import type { Options as ToucanOptions } from 'toucan-js'

declare module 'hono' {
  interface ContextVariableMap {
    sentry: Toucan
  }
}

class MockContext implements ExecutionContext {
  passThroughOnException(): void {
    throw new Error('Method not implemented.')
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  async waitUntil(promise: Promise<any>): Promise<void> {
    await promise
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  props: any
}

export type Options = Omit<ToucanOptions, 'request' | 'context'>

export const sentry = (
  options?: Options,
  callback?: (sentry: Toucan) => void
): MiddlewareHandler => {
  return async (c, next) => {
    let hasExecutionContext = true
    try {
      c.executionCtx
    } catch {
      hasExecutionContext = false
    }
    const sentry = new Toucan({
      dsn: c.env?.SENTRY_DSN ?? c.env?.NEXT_PUBLIC_SENTRY_DSN,
      requestDataOptions: {
        allowedHeaders: ['user-agent'],
        allowedSearchParams: /(.*)/,
      },
      request: c.req.raw,
      context: hasExecutionContext ? c.executionCtx : new MockContext(),
      ...options,
    })
    c.set('sentry', sentry)
    if (callback) {
      callback(sentry)
    }

    await next()
    if (c.error) {
      sentry.captureException(c.error)
    }
  }
}

export const getSentry = (c: Context): Toucan => {
  return c.get('sentry')
}

import { and, eq } from "drizzle-orm";
import { HTTPException } from "hono/http-exception";
import db from "../../database";
import { activityTable, taskTable } from "../../database/schema";
import { publishEvent } from "../../events";
import { deleteOrphanedAssets } from "../../storage/cleanup-assets";

async function deleteComment(userId: string, id: string) {
  const [existing] = await db
    .select({
      id: activityTable.id,
      content: activityTable.content,
      taskId: activityTable.taskId,
    })
    .from(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .limit(1);

  if (!existing) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [deletedComment] = await db
    .delete(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .returning();

  if (!deletedComment) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [task] = await db
    .select({ projectId: taskTable.projectId })
    .from(taskTable)
    .where(eq(taskTable.id, deletedComment.taskId))
    .limit(1);

  if (task) {
    await publishEvent("comment.deleted", {
      ...deletedComment,
      projectId: task.projectId,
      userId,
    });
  }

  deleteOrphanedAssets(existing.content, null, {
    taskId: existing.taskId,
  }).catch(() => {});

  return deletedComment;
}

export default deleteComment;

