import { AsyncLocalStorage } from "node:async_hooks";
import { EventEmitter } from "node:events";

const EVENTS = new EventEmitter();
EVENTS.setMaxListeners(100);
export const eventContext = new AsyncLocalStorage<{ initiatorId: string }>();

export type EventPayload<T = unknown> = {
  type: string;
  data: T;
  timestamp: string;
};

export async function shutdownEventBus(): Promise<void> {
  EVENTS.removeAllListeners();
}

export async function publishEvent(
  eventType: string,
  data: unknown,
): Promise<void> {
  let enhancedData = null;
  if (typeof data === "object" && data !== null) {
    const store = eventContext.getStore();
    enhancedData = { ...data, initiatorId: store?.initiatorId };
  }

  const payload: EventPayload = {
    type: eventType,
    data: enhancedData || data,
    timestamp: new Date().toISOString(),
  };

  try {
    EVENTS.emit(eventType, payload);
  } catch (error) {
    console.error("Failed to publish event:", error);
    throw error;
  }
}

export async function subscribeToEvent<T>(
  eventType: string,
  handler: (data: T) => Promise<void>,
): Promise<void> {
  try {
    EVENTS.on(eventType, async (payload: EventPayload<T>) => {
      try {
        await handler(payload.data);
      } catch (error) {
        console.error(`Error processing event ${eventType}:`, error);
      }
    });
  } catch (error) {
    console.error("Failed to subscribe to event:", error);
    throw error;
  }
}

process.on("SIGTERM", () => {
  shutdownEventBus().catch(console.error);
});

import { eq } from "drizzle-orm";
import { Hono } from "hono";
import { describeRoute, resolver, validator } from "hono-openapi";
import * as v from "valibot";
import db from "../database";
import { externalLinkTable } from "../database/schema";
import { workspaceAccess } from "../utils/workspace-access-middleware";

const externalLinkSchema = v.object({
  id: v.string(),
  taskId: v.string(),
  integrationId: v.string(),
  resourceType: v.string(),
  externalId: v.string(),
  url: v.string(),
  title: v.nullable(v.string()),
  metadata: v.any(),
  createdAt: v.date(),
  updatedAt: v.date(),
});

const externalLink = new Hono<{
  Variables: {
    userId: string;
    workspaceId: string;
  };
}>().get(
  "/task/:taskId",
  describeRoute({
    operationId: "getExternalLinksByTask",
    tags: ["External Links"],
    description: "Get all external links for a task",
    responses: {
      200: {
        description: "External links for the task",
        content: {
          "application/json": {
            schema: resolver(v.array(externalLinkSchema)),
          },
        },
      },
    },
  }),
  validator("param", v.object({ taskId: v.string() })),
  workspaceAccess.fromTaskId("taskId"),
  async (c) => {
    const { taskId } = c.req.valid("param");

    const links = await db.query.externalLinkTable.findMany({
      where: eq(externalLinkTable.taskId, taskId),
      with: {
        integration: true,
      },
    });

    const formattedLinks = links.map((link) => ({
      ...link,
      metadata: link.metadata ? JSON.parse(link.metadata) : null,
    }));

    return c.json(formattedLinks);
  },
);

export default externalLink;

import { and, eq } from "drizzle-orm";
import db from "../../database";
